import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, Badge } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  forecast?: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const lower = condition.toLowerCase();
  if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloudy') || lower.includes('cloud')) return '☁️';
  if (lower.includes('rainy') || lower.includes('rain')) return '🌧️';
  if (lower.includes('snow')) return '❄️';
  if (lower.includes('wind')) return '💨';
  if (lower.includes('thunder') || lower.includes('storm')) return '⛈️';
  if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
  return '🌡️';
};

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  forecast = [
    { day: 'Tomorrow', icon: '☀️', high: 75, low: 62 },
    { day: 'Wed', icon: '☁️', high: 68, low: 58 },
    { day: 'Thu', icon: '🌧️', high: 62, low: 55 },
    { day: 'Fri', icon: '⛈️', high: 60, low: 52 },
    { day: 'Sat', icon: '☀️', high: 70, low: 60 },
  ],
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Container maxWidth="sm" padding="0">
      <Card shadow="md" padding="0" border={true}>
        <Stack direction="vertical" gap={0}>
          {/* Header Section - Branded primary background */}
          <div
            style={{
              backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
              padding: 'var(--ggui-spacing-6, 24px)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) 0 0',
            }}
          >
            <Stack direction="vertical" gap={8} align="center">
              <Text
                variant="body"
                weight="semibold"
                color="white"
                align="center"
              >
                {city}
              </Text>
              <div
                style={{
                  display: 'flex',
                  alignItems: 'baseline',
                  gap: 'var(--ggui-spacing-4, 16px)',
                  justifyContent: 'center',
                }}
              >
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 36px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    color: 'white',
                    lineHeight: '1',
                  }}
                >
                  {temperature}°
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-3xl, 30px)',
                  }}
                >
                  {weatherEmoji}
                </Text>
              </div>
              <Text
                variant="body"
                color="rgba(255, 255, 255, 0.9)"
                align="center"
              >
                {condition}
              </Text>
            </Stack>
          </div>

          {/* Current Conditions Section */}
          <div style={{ padding: 'var(--ggui-spacing-6, 24px)' }}>
            <Stack direction="horizontal" justify="around" gap={16}>
              {/* Humidity */}
              <div
                style={{
                  flex: 1,
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  padding: 'var(--ggui-spacing-4, 16px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  textAlign: 'center',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                }}
              >
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-700, #0369a1)"
                  weight="semibold"
                >
                  Humidity
                </Text>
                <div style={{ height: 'var(--ggui-spacing-2, 8px)' }} />
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-xl, 20px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-primary-900, #0c4a6e)',
                  }}
                >
                  {humidity}%
                </Text>
              </div>

              {/* Wind Speed */}
              <div
                style={{
                  flex: 1,
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  padding: 'var(--ggui-spacing-4, 16px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  textAlign: 'center',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                }}
              >
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-700, #0369a1)"
                  weight="semibold"
                >
                  Wind
                </Text>
                <div style={{ height: 'var(--ggui-spacing-2, 8px)' }} />
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-xl, 20px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-primary-900, #0c4a6e)',
                  }}
                >
                  {windSpeed} mph
                </Text>
              </div>
            </Stack>
          </div>

          {/* Divider */}
          <div
            style={{
              height: '1px',
              backgroundColor: 'var(--ggui-color-primary-200, #bae6fd)',
            }}
          />

          {/* 5-Day Forecast Strip */}
          <div style={{ padding: 'var(--ggui-spacing-4, 16px)' }}>
            <Stack direction="vertical" gap={8}>
              <Text
                variant="caption"
                weight="semibold"
                color="var(--ggui-color-primary-700, #0369a1)"
              >
                5-DAY FORECAST
              </Text>
              <Row
                gap={8}
                justify="between"
                wrap={false}
                style={{
                  overflowX: 'auto',
                  paddingBottom: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {forecast.map((day, idx) => (
                  <div
                    key={idx}
                    style={{
                      flex: '0 0 calc(20% - 6.4px)',
                      minWidth: '70px',
                      backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-2, 8px)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                      textAlign: 'center',
                    }}
                  >
                    <Text
                      variant="caption"
                      weight="semibold"
                      color="var(--ggui-color-neutral-700, #374151)"
                      style={{ display: 'block', marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                    >
                      {day.day}
                    </Text>
                    <div
                      style={{
                        fontSize: 'var(--ggui-font-size-lg, 18px)',
                        margin: 'var(--ggui-spacing-1, 4px) 0',
                      }}
                    >
                      {day.icon}
                    </div>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-neutral-600, #4b5563)"
                      style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}
                    >
                      <span style={{ color: 'var(--ggui-color-neutral-900, #111827)', fontWeight: '600' }}>
                        {day.high}°
                      </span>
                      <span style={{ display: 'block' }}>{day.low}°</span>
                    </Text>
                  </div>
                ))}
              </Row>
            </Stack>
          </div>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button,
  Divider,
  Icon,
} from '@ggui-ai/design/primitives';

interface SatisfactionOption {
  value: string;
  label: string;
}

interface FeatureOption {
  id: string;
  label: string;
}

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: string;
  featureInterests: string[];
  comments: string;
}

interface Props {
  satisfactionLabels?: SatisfactionOption[];
  featureOptions?: FeatureOption[];
  onSubmit?: (answers: SurveyAnswers) => void;
}

interface StepHeaderProps {
  title: string;
  description: string;
}

const StepHeader = ({ title, description }: StepHeaderProps) => (
  <div>
    <Text variant="h3" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
      {title}
    </Text>
    <Text
      style={{
        color: 'var(--ggui-color-neutral-600, #4b5563)',
        fontSize: 'var(--ggui-font-size-sm, 14px)',
        marginTop: 'var(--ggui-spacing-2, 8px)',
      }}
    >
      {description}
    </Text>
  </div>
);

interface ReviewCardProps {
  title: string;
  children: React.ReactNode;
}

const ReviewCard = ({ title, children }: ReviewCardProps) => (
  <Card
    padding={16}
    border={true}
    shadow="sm"
    style={{
      backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
      borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      borderWidth: '1px',
      borderStyle: 'solid',
    }}
  >
    <Stack direction="vertical" gap={12}>
      <Text weight="semibold" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
        {title}
      </Text>
      {children}
    </Stack>
  </Card>
);

export default function GeneratedComponent({
  satisfactionLabels = [
    { value: '1', label: '1 - Very Unsatisfied' },
    { value: '2', label: '2 - Unsatisfied' },
    { value: '3', label: '3 - Neutral' },
    { value: '4', label: '4 - Satisfied' },
    { value: '5', label: '5 - Very Satisfied' },
  ],
  featureOptions = [
    { id: 'feature1', label: 'Easy to Use' },
    { id: 'feature2', label: 'Performance' },
    { id: 'feature3', label: 'Customer Support' },
    { id: 'feature4', label: 'Pricing' },
    { id: 'feature5', label: 'Features & Functions' },
  ],
  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const totalSteps = 5;

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});

  const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);

  const validateStep1 = () => {
    const newErrors: Record<string, string> = {};
    if (!name.trim()) newErrors.name = 'Name is required';
    if (!email.trim()) newErrors.email = 'Email is required';
    else if (!isValidEmail(email)) newErrors.email = 'Please enter a valid email address';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const validateStep2 = () => {
    if (!satisfactionRating) {
      setErrors({ satisfactionRating: 'Please select a rating' });
      return false;
    }
    setErrors({});
    return true;
  };

  const validateStep3 = () => {
    if (featureInterests.length === 0) {
      setErrors({ features: 'Please select at least one feature' });
      return false;
    }
    setErrors({});
    return true;
  };

  const handleNext = () => {
    let isValid = false;
    if (currentStep === 1) isValid = validateStep1();
    else if (currentStep === 2) isValid = validateStep2();
    else if (currentStep === 3) isValid = validateStep3();
    else isValid = true;

    if (isValid && currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
      setErrors({});
    }
  };

  const handlePrevious = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  };

  const handleSubmit = () => {
    const answers: SurveyAnswers = { name, email, satisfactionRating, featureInterests, comments };
    onSubmit?.(answers);
  };

  const toggleFeature = (featureId: string) => {
    setFeatureInterests(prev =>
      prev.includes(featureId) ? prev.filter(f => f !== featureId) : [...prev, featureId]
    );
  };

  const isNextDisabled = () => {
    if (currentStep === 1) return !name.trim() || !email.trim() || !isValidEmail(email);
    if (currentStep === 2) return !satisfactionRating;
    if (currentStep === 3) return featureInterests.length === 0;
    return false;
  };

  const progressPercent = Math.round(((currentStep - 1) / (totalSteps - 1)) * 100);

  const renderStep = () => {
    if (currentStep === 1) {
      return (
        <Stack direction="vertical" gap={20} role="form" aria-label="Step 1: Personal Information">
          <StepHeader title="Your Information" description="Please provide your name and email address" />
          <Input
            label="Full Name"
            placeholder="John Doe"
            value={name}
            onChange={setName}
            required
            error={errors.name}
            aria-invalid={!!errors.name}
            aria-describedby={errors.name ? 'name-error' : undefined}
          />
          {errors.name && (
            <Text id="name-error" role="alert" style={{ color: 'var(--ggui-color-error-600, #dc2626)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
              {errors.name}
            </Text>
          )}
          <Input
            label="Email Address"
            type="email"
            placeholder="john@example.com"
            value={email}
            onChange={setEmail}
            required
            error={errors.email}
            aria-invalid={!!errors.email}
            aria-describedby={errors.email ? 'email-error' : undefined}
          />
          {errors.email && (
            <Text id="email-error" role="alert" style={{ color: 'var(--ggui-color-error-600, #dc2626)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
              {errors.email}
            </Text>
          )}
        </Stack>
      );
    }

    if (currentStep === 2) {
      return (
        <Stack direction="vertical" gap={20} role="form" aria-label="Step 2: Satisfaction Rating">
          <StepHeader title="How satisfied are you with our service?" description="Your feedback helps us improve" />
          <RadioGroup
            label="Satisfaction Rating"
            value={satisfactionRating}
            onChange={setSatisfactionRating}
            options={satisfactionLabels}
            direction="vertical"
            error={errors.satisfactionRating}
            aria-invalid={!!errors.satisfactionRating}
            aria-describedby={errors.satisfactionRating ? 'satisfaction-error' : undefined}
          />
          {errors.satisfactionRating && (
            <Text id="satisfaction-error" role="alert" style={{ color: 'var(--ggui-color-error-600, #dc2626)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
              {errors.satisfactionRating}
            </Text>
          )}
        </Stack>
      );
    }

    if (currentStep === 3) {
      return (
        <Stack direction="vertical" gap={20} role="form" aria-label="Step 3: Feature Interests">
          <StepHeader title="Which features interest you most?" description="Select all that apply" />
          <Stack direction="vertical" gap={12}>
            {featureOptions.map(feature => (
              <Checkbox
                key={feature.id}
                label={feature.label}
                checked={featureInterests.includes(feature.id)}
                onChange={() => toggleFeature(feature.id)}
              />
            ))}
          </Stack>
          {errors.features && (
            <Text id="features-error" role="alert" style={{ color: 'var(--ggui-color-error-600, #dc2626)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
              {errors.features}
            </Text>
          )}
        </Stack>
      );
    }

    if (currentStep === 4) {
      return (
        <Stack direction="vertical" gap={20} role="form" aria-label="Step 4: Additional Comments">
          <StepHeader title="Any additional comments?" description="This is optional and helps us understand your experience better" />
          <TextArea
            label="Comments"
            placeholder="Tell us what you think..."
            value={comments}
            onChange={setComments}
            rows={5}
            maxLength={500}
          />
          <Row justify="between" align="center">
            <Text style={{ color: 'var(--ggui-color-neutral-500, #6b7280)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
              {comments.length} / 500 characters
            </Text>
            {comments.length >= 450 && (
              <Text style={{ color: 'var(--ggui-color-warning-600, #d97706)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
                Approaching limit
              </Text>
            )}
          </Row>
        </Stack>
      );
    }

    return (
      <Stack direction="vertical" gap={20}>
        <div>
          <Text variant="h3" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
            Review Your Answers
          </Text>
          <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)', fontSize: 'var(--ggui-font-size-sm, 14px)', marginTop: 'var(--ggui-spacing-2, 8px)' }}>
            Please review your responses before submitting
          </Text>
        </div>
        <ReviewCard title="Personal Information">
          <Row justify="between">
            <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>Name:</Text>
            <Text weight="semibold">{name}</Text>
          </Row>
          <Row justify="between">
            <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>Email:</Text>
            <Text weight="semibold">{email}</Text>
          </Row>
        </ReviewCard>
        <ReviewCard title="Satisfaction Rating">
          <Row justify="between">
            <Text style={{ color: 'var(--ggui-color-neutral-600, #4b5563)' }}>Rating:</Text>
            <Text weight="semibold">
              {satisfactionLabels.find(opt => opt.value === satisfactionRating)?.label || 'Not selected'}
            </Text>
          </Row>
        </ReviewCard>
        <ReviewCard title="Feature Interests">
          {featureInterests.length > 0 ? (
            <Stack direction="vertical" gap={8}>
              {featureInterests.map(featureId => {
                const feature = featureOptions.find(f => f.id === featureId);
                return (
                  <Row key={featureId} gap={8} align="center">
                    <Icon name="check" size={16} color="var(--ggui-color-success-600, #16a34a)" />
                    <Text>{feature?.label}</Text>
                  </Row>
                );
              })}
            </Stack>
          ) : (
            <Text style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>No features selected</Text>
          )}
        </ReviewCard>
        <ReviewCard title="Additional Comments">
          {comments ? (
            <Text style={{ whiteSpace: 'pre-wrap' }}>{comments}</Text>
          ) : (
            <Text style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>No comments provided</Text>
          )}
        </ReviewCard>
      </Stack>
    );
  };

  return (
    <Container maxWidth="lg">
      <Card padding={24} shadow="md">
        <Stack direction="vertical" gap={24}>
          <div>
            <Text variant="h2" align="center" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
              Customer Survey
            </Text>
            <Text align="center" style={{ color: 'var(--ggui-color-neutral-600, #4b5563)', marginTop: 'var(--ggui-spacing-2, 8px)' }}>
              Your feedback is valuable to us
            </Text>
          </div>

          <Stack direction="vertical" gap={8}>
            <Row justify="between" align="center">
              <Text style={{ fontSize: 'var(--ggui-font-size-sm, 14px)', fontWeight: 'var(--ggui-font-weight-medium, 500)', color: 'var(--ggui-color-primary-700, #0369a1)' }}>
                Step {currentStep} of {totalSteps}
              </Text>
              <Text style={{ fontSize: 'var(--ggui-font-size-sm, 14px)', color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                {progressPercent}%
              </Text>
            </Row>

            <div
              style={{
                width: '100%',
                height: '8px',
                backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                overflow: 'hidden',
              }}
            >
              <div
                style={{
                  width: progressPercent + '%',
                  height: '100%',
                  backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
                  transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                }}
              />
            </div>
          </Stack>

          <Divider />
          {renderStep()}
          <Divider />

          <Row justify="between" gap={12}>
            <Button
              variant="outline"
              onClick={handlePrevious}
              disabled={currentStep === 1}
              leftIcon={<Icon name="chevron-left" size={16} />}
            >
              Back
            </Button>

            {currentStep === totalSteps ? (
              <Button
                variant="primary"
                onClick={handleSubmit}
                rightIcon={<Icon name="check" size={16} />}
              >
                Submit Survey
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={isNextDisabled()}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useCallback } from 'react';
import {
  Container, Card, Stack, Row, Text, Button, Input, Select,
  Icon, Badge, Divider, MotionKeyframes, useMotion,
} from '@ggui-ai/design/primitives';

interface TaskType {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: { name: string; initials: string };
  dueDate?: string;
  column: 'todo' | 'inprogress' | 'done';
}

interface Props {
  initialTasks?: TaskType[];
  onTaskUpdate?: (task: TaskType) => void;
}

const COLUMNS = [{ id: 'todo', name: 'To Do' }, { id: 'inprogress', name: 'In Progress' }, { id: 'done', name: 'Done' }];
const priorityVariants: Record<string, string> = { low: 'success', medium: 'warning', high: 'error' };

function SummaryBar({ totalTasks, completedTasks }: { totalTasks: number; completedTasks: number }) {
  const progress = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;
  return (
    <Row gap={24} justify="start" align="center" style={{
      backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
      padding: 'var(--ggui-spacing-4, 16px)',
      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
      borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
    }}>
      <Stack direction="vertical" gap={4}>
        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Total Tasks</Text>
        <Text variant="h2" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">{totalTasks}</Text>
      </Stack>
      <Divider orientation="vertical" margin={0} />
      <Stack direction="vertical" gap={4}>
        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Completed</Text>
        <Text variant="h2" weight="bold" color="var(--ggui-color-success-600, #16a34a)">{completedTasks}</Text>
      </Stack>
      <Divider orientation="vertical" margin={0} />
      <Stack direction="vertical" gap={4}>
        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Progress</Text>
        <Text variant="h2" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">{progress}%</Text>
      </Stack>
    </Row>
  );
}

interface TaskCardProps {
  task: TaskType;
  isEditing: boolean;
  editTitle: string;
  onStartEdit: (task: TaskType) => void;
  onSaveEdit: (id: string) => void;
  onCancelEdit: () => void;
  onEditChange: (val: string) => void;
  onMoveTask: (id: string, col: string) => void;
}

function TaskCard({
  task, isEditing, editTitle, onStartEdit, onSaveEdit,
  onCancelEdit, onEditChange, onMoveTask,
}: TaskCardProps) {
  return (
    <Card padding="var(--ggui-spacing-4, 16px)" shadow="sm" border style={{
      marginBottom: 'var(--ggui-spacing-2, 8px)',
      borderColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
      transition: 'box-shadow 200ms',
    }} onMouseEnter={(e) => { e.currentTarget.style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'; }} onMouseLeave={(e) => { e.currentTarget.style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'; }}>
      <Stack direction="vertical" gap={8}>
        {isEditing ? (
          <Stack direction="horizontal" gap={6}>
            <Input value={editTitle} onChange={onEditChange} placeholder="Task title" autoFocus />
            <Button variant="primary" size="sm" onClick={() => onSaveEdit(task.id)}><Icon name="check" size={16} /></Button>
            <Button variant="outline" size="sm" onClick={onCancelEdit}><Icon name="x" size={16} /></Button>
          </Stack>
        ) : (
          <Row justify="between" align="start">
            <Text variant="body" weight="semibold" style={{ flex: 1, cursor: 'pointer', color: 'var(--ggui-color-neutral-900, #111827)', wordBreak: 'break-word' }} onDoubleClick={() => onStartEdit(task)}>{task.title}</Text>
            <Button variant="ghost" size="sm" onClick={() => onStartEdit(task)}><Icon name="settings" size={14} /></Button>
          </Row>
        )}
        <Badge variant={priorityVariants[task.priority] as any}>{task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}</Badge>
        {(task.assignee || task.dueDate) && (
          <Stack direction="horizontal" gap={12} justify="between" align="center">
            {task.assignee && (<div style={{ width: 32, height: 32, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '12px', fontWeight: 'var(--ggui-font-weight-semibold, 600)', color: 'var(--ggui-color-primary-700, #0369a1)' }} title={task.assignee.name}>{task.assignee.initials}</div>)}
            {task.dueDate && (<Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{ whiteSpace: 'nowrap' }}>{new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</Text>)}
          </Stack>
        )}
        <Select value={task.column} onChange={(col) => onMoveTask(task.id, col)} options={COLUMNS.map((c) => ({ value: c.id, label: c.name }))} label="" placeholder="Move..." />
      </Stack>
    </Card>
  );
}

interface AddFormProps {
  columnId: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  onTitleChange: (val: string) => void;
  onPriorityChange: (val: 'low' | 'medium' | 'high') => void;
  onAdd: (colId: string) => void;
  onCancel: () => void;
}

function AddTaskForm({ columnId, title, priority, onTitleChange, onPriorityChange, onAdd, onCancel }: AddFormProps) {
  return (
    <Card padding="var(--ggui-spacing-4, 16px)" border style={{
      borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
    }}>
      <Stack direction="vertical" gap={12}>
        <Input value={title} onChange={onTitleChange} placeholder="Enter task title..." label="Task Title" autoFocus />
        <Select value={priority} onChange={(val) => onPriorityChange(val as any)} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} label="Priority" />
        <Row gap={8} justify="end">
          <Button variant="outline" size="sm" onClick={onCancel}>Cancel</Button>
          <Button variant="primary" size="sm" onClick={() => onAdd(columnId)} disabled={!title.trim()}><Icon name="plus" size={14} />Add</Button>
        </Row>
      </Stack>
    </Card>
  );
}

export default function GeneratedComponent({ initialTasks = [], onTaskUpdate }: Props) {
  const { motionEnabled } = useMotion();
  const [tasks, setTasks] = useState<TaskType[]>(initialTasks);
  const [addingCol, setAddingCol] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editId, setEditId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  const getTasksForCol = useCallback((colId: string) => tasks.filter((t) => t.column === colId), [tasks]);
  const totTasks = tasks.length;
  const compTasks = getTasksForCol('done').length;

  const handleAdd = useCallback((colId: string) => {
    if (!newTitle.trim()) return;
    const timestamp = Date.now();
    const newTask: TaskType = {
      id: 'task-' + String(timestamp),
      title: newTitle.trim(),
      priority: newPriority,
      column: colId as any,
    };
    setTasks((p) => [...p, newTask]);
    onTaskUpdate?.(newTask);
    setNewTitle('');
    setNewPriority('medium');
    setAddingCol(null);
  }, [newTitle, newPriority, onTaskUpdate]);

  const handleMove = useCallback((taskId: string, newCol: string) => {
    const task = tasks.find((t) => t.id === taskId);
    if (task) {
      setTasks((p) => p.map((t) => (t.id === taskId ? { ...t, column: newCol as any } : t)));
      onTaskUpdate?.({ ...task, column: newCol as any });
    }
  }, [tasks, onTaskUpdate]);

  const handleStartEdit = (task: TaskType) => { setEditId(task.id); setEditTitle(task.title); };
  const handleSaveEdit = (id: string) => {
    if (!editTitle.trim()) return;
    const task = tasks.find((t) => t.id === id);
    if (task) {
      setTasks((p) => p.map((t) => (t.id === id ? { ...t, title: editTitle.trim() } : t)));
      onTaskUpdate?.({ ...task, title: editTitle.trim() });
    }
    setEditId(null);
    setEditTitle('');
  };
  const handleCancelEdit = () => { setEditId(null); setEditTitle(''); };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack direction="vertical" gap={24}>
        <Stack direction="vertical" gap={8}>
          <Text variant="h1" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">Kanban Board</Text>
          <Divider margin={0} />
        </Stack>
        <SummaryBar totalTasks={totTasks} completedTasks={compTasks} />
        <Row gap={24} align="start" justify="start" wrap style={{ minHeight: '500px' }}>
          {COLUMNS.map((col) => {
            const colTasks = getTasksForCol(col.id);
            const isAdding = addingCol === col.id;
            return (
              <div key={col.id} style={{ flex: '0 1 calc(33.333% - 16px)', minWidth: '300px', display: 'flex', flexDirection: 'column' }}>
                <Card padding={0} border shadow="none" style={{ height: '100%', display: 'flex', flexDirection: 'column', borderColor: 'var(--ggui-color-neutral-200, #e5e7eb)', backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)' }}>
                  <div style={{ padding: 'var(--ggui-spacing-4, 16px)', backgroundColor: 'var(--ggui-color-neutral-100, #f3f4f6)', borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <Stack direction="horizontal" gap={8} align="center">
                      <Text variant="h3" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">{col.name}</Text>
                      <Badge variant="secondary">{colTasks.length}</Badge>
                    </Stack>
                  </div>
                  <div style={{ flex: 1, overflow: 'auto', padding: 'var(--ggui-spacing-4, 16px)', display: 'flex', flexDirection: 'column' }}>
                    <Stack direction="vertical" gap={8}>
                      {colTasks.map((task) => (<TaskCard key={task.id} task={task} isEditing={editId === task.id} editTitle={editTitle} onStartEdit={handleStartEdit} onSaveEdit={handleSaveEdit} onCancelEdit={handleCancelEdit} onEditChange={setEditTitle} onMoveTask={handleMove} />))}
                      {isAdding && (<AddTaskForm columnId={col.id} title={newTitle} priority={newPriority} onTitleChange={setNewTitle} onPriorityChange={setNewPriority} onAdd={handleAdd} onCancel={() => setAddingCol(null)} />)}
                      {colTasks.length === 0 && !isAdding && (<div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '200px', color: 'var(--ggui-color-neutral-400, #9ca3af)', textAlign: 'center' }}><Text variant="caption">No tasks yet</Text></div>)}
                    </Stack>
                  </div>
                  {!isAdding && (<div style={{ padding: 'var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}><Button variant="outline" size="sm" fullWidth leftIcon={<Icon name="plus" size={14} />} onClick={() => setAddingCol(col.id)}>Add Task</Button></div>)}
                </Card>
              </div>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

