export default function GeneratedComponent({ elements = DEFAULT_ELEMENTS, onElementSelect }: Props) {
  const { motionEnabled } = useMotion();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.symbol.toLowerCase().includes(query) ||
        el.name.toLowerCase().includes(query) ||
        el.atomicNumber.toString().includes(query)
    );
  }, [elements, searchQuery]);

  // Create a map for quick lookup of filtered elements
  const filteredSet = new Set(filteredElements.map((el) => el.atomicNumber));

  // Handle element click
  const handleElementClick = (element: Element) => {
    setSelectedElement(element);
    onElementSelect?.(element);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />

      <Stack direction="vertical" gap={24}>
        {/* Header */}
        <Stack direction="vertical" gap={8}>
          <Text variant="h1" color="var(--ggui-color-primary-900, #0c4a6e)">
            Interactive Periodic Table
          </Text>
          <Text color="var(--ggui-color-neutral-600, #4b5563)">
            Click on any element to view detailed information
          </Text>
        </Stack>

        {/* Search Input */}
        <Box>
          <Input
            label="Search elements"
            placeholder="Search by name, symbol, or atomic number..."
            value={searchQuery}
            onChange={setSearchQuery}
            type="text"
          />
          {searchQuery && (
            <Text color="var(--ggui-color-neutral-500, #6b7280)" variant="caption" style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
              Found {filteredElements.length} element{filteredElements.length !== 1 ? 's' : ''}
            </Text>
          )}
        </Box>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4, 16px)" border={true} shadow="sm">
          <Stack direction="vertical" gap={12}>
            <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">
              Legend
            </Text>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: 'var(--ggui-spacing-2, 8px)' }}>
              {Object.entries(CATEGORY_COLORS).map(([category, colors]) => (
                <Row key={category} gap={8} align="center">
                  <div
                    style={{
                      width: 24,
                      height: 24,
                      backgroundColor: colors.bg,
                      border: '2px solid ' + colors.borderRgb,
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    }}
                  />
                  <Text variant="caption" color="var(--ggui-color-neutral-700, #374151)">
                    {colors.label}
                  </Text>
                </Row>
              ))}
            </div>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
            gap: 'var(--ggui-spacing-2, 8px)',
            padding: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
          }}
        >
          {filteredElements.map((element) => {
            const colors = CATEGORY_COLORS[element.category];
            const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
            const isVisible = filteredSet.has(element.atomicNumber);

            return (
              <button
                key={element.atomicNumber}
                onClick={() => handleElementClick(element)}
                style={{
                  ...getElementButtonStyle(colors, isSelected, element.column),
                  gridRow: element.row + 1,
                  animation: motionEnabled && isVisible ? animation.fadeIn : 'none',
                  opacity: isVisible ? 1 : 0.3,
                  pointerEvents: isVisible ? 'auto' : 'none',
                } as React.CSSProperties}
                disabled={!isVisible}
              >
                <div style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', opacity: 0.8, fontWeight: 'var(--ggui-font-weight-normal, 400)' }}>
                  {element.atomicNumber}
                </div>
                <div style={{ fontSize: 'var(--ggui-font-size-lg, 18px)', fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
                  {element.symbol}
                </div>
                <div style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', opacity: 0.9 }}>
                  {element.atomicWeight.toFixed(3)}
                </div>
              </button>
            );
          })}
        </div>

        {/* Detail Panel */}
        {selectedElement && (
          <Card
            padding="var(--ggui-spacing-6, 24px)"
            shadow="md"
            border={true}
            style={{
              animation: motionEnabled ? animation.slideInUp : 'none',
              borderLeft: '4px solid ' + CATEGORY_COLORS[selectedElement.category].bg,
            } as React.CSSProperties}
          >
            <Stack direction="vertical" gap={16}>
              <Row justify="between" align="center">
                <Stack direction="vertical" gap={4}>
                  <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)">
                    {selectedElement.name}
                  </Text>
                  <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
                    {CATEGORY_COLORS[selectedElement.category].label}
                  </Text>
                </Stack>
                <Button
                  variant="ghost"
                  onClick={() => setSelectedElement(null)}
                  style={{ padding: 'var(--ggui-spacing-2, 8px)' }}
                >
                  <Icon name="x" size={20} />
                </Button>
              </Row>

              <Divider />

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--ggui-spacing-4, 16px)' }}>
                <Stack direction="vertical" gap={8}>
                  <Stack direction="vertical" gap={2}>
                    <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                      Atomic Number
                    </Text>
                    <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">
                      {selectedElement.atomicNumber}
                    </Text>
                  </Stack>

                  <Stack direction="vertical" gap={2}>
                    <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                      Symbol
                    </Text>
                    <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">
                      {selectedElement.symbol}
                    </Text>
                  </Stack>

                  <Stack direction="vertical" gap={2}>
                    <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                      Atomic Weight
                    </Text>
                    <Text variant="body" color="var(--ggui-color-neutral-900, #111827)">
                      {selectedElement.atomicWeight.toFixed(3)} u
                    </Text>
                  </Stack>
                </Stack>

                <Stack direction="vertical" gap={8}>
                  <Stack direction="vertical" gap={2}>
                    <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                      Period
                    </Text>
                    <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">
                      {selectedElement.row}
                    </Text>
                  </Stack>

                  <Stack direction="vertical" gap={2}>
                    <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                      Group
                    </Text>
                    <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">
                      {selectedElement.column}
                    </Text>
                  </Stack>

                  <Stack direction="vertical" gap={2}>
                    <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                      Category
                    </Text>
                    <Text variant="body" color="var(--ggui-color-neutral-900, #111827)">
                      {CATEGORY_COLORS[selectedElement.category].label}
                    </Text>
                  </Stack>
                </Stack>
              </div>

              <Divider />

              <Stack direction="vertical" gap={8}>
                <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                  Electron Configuration
                </Text>
                <Card
                  padding="var(--ggui-spacing-3, 12px)"
                  shadow="none"
                  border={true}
                  style={{
                    backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                    borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
                  } as React.CSSProperties}
                >
                  <Text
                    variant="body"
                    color="var(--ggui-color-primary-900, #0c4a6e)"
                    style={{ fontFamily: 'monospace', wordBreak: 'break-all' }}
                  >
                    {selectedElement.electronConfiguration}
                  </Text>
                </Card>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Empty state for search */}
        {searchQuery && filteredElements.length === 0 && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="sm" border={true}>
            <Stack direction="vertical" gap={8} align="center">
              <Icon name="search" size={32} color="var(--ggui-color-neutral-300, #d1d5db)" />
              <Text color="var(--ggui-color-neutral-500, #6b7280)" align="center">
                No elements found matching "{searchQuery}"
              </Text>
              <Button variant="outline" onClick={() => setSearchQuery('')}>
                Clear Search
              </Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Icon,
  Divider,
  Table,
  Tabs,
  Badge,
} from '@ggui-ai/design/primitives';

interface Review {
  id: string;
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Specification {
  key: string;
  value: string;
}

interface Props {
  productId: string;
  productName?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  stockStatus?: 'in-stock' | 'low-stock' | 'out-of-stock';
  stockQuantity?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

// Helper function to render star rating
const RatingStars = ({ rating, size = 16 }: { rating: number; size?: number }) => {
  const stars = Array.from({ length: 5 }, (_, i) => i < Math.floor(rating));
  return (
    <Row gap={2} align="center">
      {stars.map((filled, i) => (
        <Icon
          key={i}
          name="check"
          size={size}
          color={
            filled
              ? 'var(--ggui-color-warning-500, #f59e0b)'
              : 'var(--ggui-color-neutral-300, #d1d5db)'
          }
          style={{
            opacity: filled ? 1 : 0.3,
          }}
        />
      ))}
    </Row>
  );
};

// Helper function to format price
const formatPrice = (price: number, currencySymbol: string) => {
  return currencySymbol + price.toFixed(2);
};

// Helper function to get currency symbol
const getCurrencySymbol = (currency: string) => {
  const currencySymbols: Record<string, string> = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
    INR: '₹',
  };
  return currencySymbols[currency] || currency;
};

export default function GeneratedComponent({
  productId,
  productName = 'Premium Wireless Headphones',
  price = 129.99,
  currency = 'USD',
  rating = 4.5,
  reviewCount = 128,
  stockStatus = 'in-stock',
  stockQuantity = 45,
  description = 'Experience premium audio quality with our state-of-the-art wireless headphones. Featuring active noise cancellation, 30-hour battery life, and premium comfort for all-day listening.',
  specifications = [
    { key: 'Weight', value: '250g' },
    { key: 'Battery Life', value: '30 hours' },
    { key: 'Connectivity', value: 'Bluetooth 5.0' },
    { key: 'Driver Size', value: '40mm' },
    { key: 'Frequency Range', value: '20Hz - 20kHz' },
  ],
  reviews = [
    {
      id: '1',
      author: 'Sarah Johnson',
      rating: 5,
      text: 'Excellent sound quality and very comfortable. Best purchase I\'ve made this year!',
      date: '2024-01-15',
    },
    {
      id: '2',
      author: 'Michael Chen',
      rating: 4,
      text: 'Great headphones, battery life is impressive. Slightly tight headband at first but breaks in nicely.',
      date: '2024-01-10',
    },
    {
      id: '3',
      author: 'Emma Davis',
      rating: 5,
      text: 'Perfect for travel and work. The noise cancellation is fantastic.',
      date: '2024-01-05',
    },
  ],
  onAddToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const isOutOfStock = stockStatus === 'out-of-stock';
  const currencySymbol = getCurrencySymbol(currency);

  const handleIncrement = () => {
    if (quantity < (stockQuantity || 1)) {
      setQuantity(q => q + 1);
    }
  };

  const handleDecrement = () => {
    if (quantity > 1) {
      setQuantity(q => q - 1);
    }
  };

  const handleAddToCart = () => {
    if (onAddToCart && !isOutOfStock) {
      onAddToCart({ productId, quantity });
    }
  };

  // Get stock badge variant based on status
  const getStockBadgeVariant = () => {
    switch (stockStatus) {
      case 'in-stock':
        return 'success';
      case 'low-stock':
        return 'warning';
      case 'out-of-stock':
        return 'error';
      default:
        return 'default';
    }
  };

  const getStockBadgeText = () => {
    switch (stockStatus) {
      case 'in-stock':
        return 'In Stock';
      case 'low-stock':
        return 'Low Stock';
      case 'out-of-stock':
        return 'Out of Stock';
      default:
        return 'Unknown';
    }
  };

  // Tabs content
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Stack direction="vertical" gap={16}>
          <Text>{description}</Text>
        </Stack>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Table
          columns={[
            { key: 'key', header: 'Property', width: '40%' },
            { key: 'value', header: 'Value', width: '60%' },
          ]}
          data={specifications}
          compact
          bordered
        />
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack direction="vertical" gap={20}>
          {reviews && reviews.length > 0 ? (
            reviews.map((review) => (
              <Card
                key={review.id}
                padding={16}
                shadow="none"
                border={true}
                style={{
                  borderColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
                }}
              >
                <Stack direction="vertical" gap={12}>
                  <Row justify="between" align="start">
                    <Stack direction="vertical" gap={4}>
                      <Text weight="semibold">{review.author}</Text>
                      <RatingStars rating={review.rating} size={14} />
                    </Stack>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-neutral-500, #6b7280)"
                    >
                      {new Date(review.date).toLocaleDateString()}
                    </Text>
                  </Row>
                  <Text>{review.text}</Text>
                </Stack>
              </Card>
            ))
          ) : (
            <Text color="var(--ggui-color-neutral-500, #6b7280)">
              No reviews yet. Be the first to review this product!
            </Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)">
      <Stack direction="vertical" gap={32}>
        {/* Top Section: Image, Title, Price, Rating, Stock */}
        <Row
          gap={32}
          align="start"
          wrap={true}
        >
          {/* Product Image Placeholder */}
          <div
            style={{
              flex: '1 1 300px',
              minHeight: '400px',
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
              textAlign: 'center',
              padding: 'var(--ggui-spacing-6, 24px)',
            }}
          >
            <Stack direction="vertical" gap={12} align="center">
              <div
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  color: 'var(--ggui-color-primary-300, #7dd3fc)',
                }}
              >
                📦
              </div>
              <Text
                variant="label"
                color="var(--ggui-color-primary-700, #0369a1)"
              >
                {productName}
              </Text>
            </Stack>
          </div>

          {/* Product Details */}
          <Stack direction="vertical" gap={20} style={{ flex: '1 1 300px' }}>
            {/* Title */}
            <Stack direction="vertical" gap={8}>
              <Text as="h1" variant="h2" weight="bold">
                {productName}
              </Text>
            </Stack>

            {/* Rating & Review Count */}
            <Row gap={12} align="center">
              <RatingStars rating={rating} size={18} />
              <Text
                variant="label"
                color="var(--ggui-color-neutral-600, #4b5563)"
              >
                {rating.toFixed(1)} ({reviewCount} reviews)
              </Text>
            </Row>

            {/* Price */}
            <Stack direction="vertical" gap={4}>
              <Text
                style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}
              >
                {formatPrice(price, currencySymbol)}
              </Text>
            </Stack>

            {/* Stock Status Badge */}
            <Badge variant={getStockBadgeVariant()}>
              {getStockBadgeText()}
            </Badge>

            <Divider margin={16} />

            {/* Quantity Selector */}
            <Stack direction="vertical" gap={12}>
              <Text as="label" weight="semibold">
                Quantity
              </Text>
              <Row gap={8} align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleDecrement}
                  disabled={quantity <= 1 || isOutOfStock}
                  aria-label="Decrease quantity"
                >
                  <Icon name="minus" size={16} />
                </Button>
                <div
                  style={{
                    minWidth: '50px',
                    textAlign: 'center',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                  }}
                >
                  <Text weight="medium">{quantity}</Text>
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleIncrement}
                  disabled={quantity >= (stockQuantity || 1) || isOutOfStock}
                  aria-label="Increase quantity"
                >
                  <Icon name="plus" size={16} />
                </Button>
              </Row>
              {stockQuantity && stockQuantity < 10 && stockStatus === 'low-stock' && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-warning-600, #d97706)"
                >
                  Only {stockQuantity} left in stock
                </Text>
              )}
            </Stack>

            <Divider margin={16} />

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={isOutOfStock}
              fullWidth
              style={{
                backgroundColor: isOutOfStock
                  ? 'var(--ggui-color-neutral-300, #d1d5db)'
                  : 'var(--ggui-color-primary-600, #0284c7)',
                cursor: isOutOfStock ? 'not-allowed' : 'pointer',
              }}
            >
              {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Row>

        <Divider margin={24} />

        {/* Middle Section: Tabs */}
        <Stack direction="vertical" gap={20}>
          <Tabs
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            size="md"
          />
        </Stack>
      </Stack>
    </Container>
  );
}

