import { useState, useEffect, useRef } from 'react';
import {
  Container,
  Row,
  Text,
  Input,
  Button,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface User {
  id: string;
  name: string;
}

interface Message {
  id: string;
  sender: string;
  text: string;
  timestamp: string;
  senderId?: string;
}

interface TypingUser {
  [key: string]: boolean;
}

interface Props {
  title?: string;
  participants?: number;
  initialMessages?: Message[];
  user?: User;
  onSend?: (data: { text: string; timestamp: string }) => void;
  onNewMessage?: (message: Message) => void;
  onTyping?: (user: string) => void;
}

let messageCounter = 0;

const generateId = () => {
  messageCounter += 1;
  const parts = ['msg', 'id', messageCounter.toString()];
  return parts.join('-');
};

const getAnimationDelay = (index: number): string => {
  const baseDelay = 0.2;
  const multiplied = index * baseDelay;
  return multiplied.toString() + 's';
};

export default function GeneratedComponent({
  title = 'Chat',
  participants = 2,
  initialMessages = [],
  user = { id: 'user-1', name: 'You' },
  onSend,
  onNewMessage,
  onTyping,
}: Props) {
  const { motionEnabled } = useMotion();
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<TypingUser>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const typingTimersRef = useRef<Record<string, NodeJS.Timeout>>({});

  // Auto-scroll to bottom when messages change
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, typingUsers]);

  // Listen for real-time data events via props callback
  const handleReceiveMessage = (newMessage: Message) => {
    const messageWithId = {
      ...newMessage,
      id: newMessage.id || generateId(),
      senderId: newMessage.sender === user.name ? user.id : undefined,
    };
    setMessages((prev) => [...prev, messageWithId]);
  };

  const handleReceiveTyping = (typingUser: string) => {
    setTypingUsers((prev) => ({
      ...prev,
      [typingUser]: true,
    }));

    // Clear existing timer for this user if any
    if (typingTimersRef.current[typingUser]) {
      clearTimeout(typingTimersRef.current[typingUser]);
    }

    // Set new timer
    const timer = setTimeout(() => {
      setTypingUsers((prev) => {
        const updated = { ...prev };
        delete updated[typingUser];
        return updated;
      });
      delete typingTimersRef.current[typingUser];
    }, 3000);

    typingTimersRef.current[typingUser] = timer;
  };

  const handleSend = () => {
    if (!inputValue.trim()) return;

    const timestamp = new Date().toISOString();
    const newMessage: Message = {
      id: generateId(),
      sender: user.name,
      text: inputValue,
      timestamp,
      senderId: user.id,
    };

    // Add message to local state
    setMessages((prev) => [...prev, newMessage]);

    // Call callbacks
    if (onSend) {
      onSend({ text: inputValue, timestamp });
    }
    if (onNewMessage) {
      onNewMessage(newMessage);
    }

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
