  Snowy: '❄️',
  Stormy: '⛈️',
  PartlyCloudy: '⛅',
  Windy: '💨',
  Foggy: '🌫️',
};

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  location?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: 'C' | 'F';
  forecast?: ForecastDay[];
}

export default function GeneratedComponent({
  location = "San Francisco, CA",
  temperature = 72,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "F",
  forecast = [
    { day: "Mon", condition: "Sunny", high: 75, low: 58 },
