      errs.email = "Email is required";
    } else if (!validateEmail(data.email)) {
      errs.email = "Please enter a valid email address";
    }
    if (!data.satisfaction) errs.satisfaction = "Please select a rating";
    return errs;
  }, [data]);

  const isStepValid = useMemo(() => {
    switch (step) {
      case 1: return !errors.name && !errors.email;
      case 2: return !errors.satisfaction;
      case 3: return true; // Optional choice
      case 4: return data.comments.length <= 500;
      default: return true;
    }
  }, [step, errors, data]);

  const updateField = (field: keyof SurveyData, value: any) => {
    setData(prev => ({ ...prev, [field]: value }));
  };

  const handleNext = () => {
    if (isStepValid && step < totalSteps) {
      setStep(s => s + 1);
    }
  };

  const handleBack = () => {
    if (step > 1) {
      setStep(s => s - 1);
    }
  };

  const handleSubmit = () => {
    if (onSubmit) {
      onSubmit(data);
    }
  };

  const toggleFeature = (val: string) => {
    const current = [...data.features];
    const index = current.indexOf(val);
    if (index > -1) {
      current.splice(index, 1);
    } else {
      current.push(val);
    }
    updateField('features', current);
  };

  const renderProgressBar = () => {
    const progress = (step / totalSteps) * 100;
    return (
      <Stack gap={8} style={{ marginBottom: 'var(--ggui-spacing-6, 24px)' }}>
        <Row justify="between" align="center">
          <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
            STEP {step} OF {totalSteps}
          </Text>
          <Badge variant="primary">
            {Math.round(progress) + '% Complete'}
          </Badge>
        </Row>
        <div style={{
          height: 8,
          width: '100%',
          backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          overflow: 'hidden'
        }}>
          <div style={{
            height: '100%',
            width: progress + '%',
            backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
            transition: transition.normal,
            borderRadius: 'var(--ggui-shape-radius-full, 9999px)'
          }} />
        </div>
      </Stack>
    );
  };

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={20} role="form" aria-label="Step 1: Contact Information">
            <Text variant="h3">Contact Information</Text>
            <Input
              label="Full Name"
              id="survey-name"
              placeholder="e.g. John Doe"
              value={data.name}
              onChange={(v) => updateField('name', v)}
              error={touched.name ? errors.name : undefined}
              required
              onBlur={() => setTouched(t => ({ ...t, name: true }))}
            />
            <Input
              label="Email Address"
              id="survey-email"
              type="email"
              placeholder="john@example.com"
              value={data.email}
              onChange={(v) => updateField('email', v)}
              error={touched.email ? errors.email : undefined}
              required
              onBlur={() => setTouched(t => ({ ...t, email: true }))}
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap={20} role="form" aria-label="Step 2: Satisfaction Rating">
            <Text variant="h3">Overall Satisfaction</Text>
            <Text color="var(--ggui-color-neutral-500, #6b7280)">
              On a scale of 1 to 5, how satisfied are you with our product?
            </Text>
            <RadioGroup
              value={data.satisfaction}
              onChange={(v) => updateField('satisfaction', v)}
              options={Object.entries(satisfactionLabels).map(([val, label]) => ({
                value: val,
                label: val + ' - ' + label
              }))}
              error={touched.satisfaction ? errors.satisfaction : undefined}
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={20} role="form" aria-label="Step 3: Feature Interests">
            <Text variant="h3">Feature Interests</Text>
            <Text color="var(--ggui-color-neutral-500, #6b7280)">
              Which features are most important to you? (Select all that apply)
            </Text>
            <Stack gap={12}>
              {featureOptions.map((opt) => (
                <Checkbox
                  key={opt.value}
                  label={opt.label}
                  checked={data.features.includes(opt.value)}
                  onChange={() => toggleFeature(opt.value)}
                />
              ))}
            </Stack>
          </Stack>
        );
      case 4:
        return (
          <Stack gap={20} role="form" aria-label="Step 4: Additional Comments">
            <Text variant="h3">Additional Feedback</Text>
            <TextArea
              label="Comments"
              id="survey-comments"
              placeholder="Tell us more about your experience..."
              value={data.comments}
              onChange={(v) => updateField('comments', v)}
              maxLength={500}
              rows={6}
              helperText={data.comments.length + ' / 500 characters'}
            />
          </Stack>
        );
      case 5:
        return (
          <Stack gap={20} role="region" aria-label="Final Review">
            <Text variant="h3">Review Your Answers</Text>
            <Card padding={16} border background="var(--ggui-color-primary-50, #f0f9ff)">
              <Stack gap={16}>
                <div>
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Contact</Text>
                  <Text>{data.name + ' (' + data.email + ')'}</Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Satisfaction</Text>
                  <Text>{data.satisfaction ? data.satisfaction + ' - ' + satisfactionLabels[data.satisfaction] : 'Not provided'}</Text>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Interests</Text>
                  <Row gap={4} wrap>
                    {data.features.length > 0 ? (
                      data.features.map(f => (
                        <Badge key={f} variant="info">
                          {featureOptions.find(opt => opt.value === f)?.label || f}
                        </Badge>
                      ))
                    ) : (
                      <Text color="var(--ggui-color-neutral-500, #6b7280)">None selected</Text>
                    )}
                  </Row>
                </div>
                <Divider />
                <div>
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Comments</Text>
                  <Text>{data.comments || 'No comments'}</Text>
                </div>
              </Stack>
            </Card>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        style={{
          borderTop: '4px solid var(--ggui-color-primary-600, #0284c7)',
          animation: motionEnabled ? animation.fadeIn : 'none'
        }}
      >
        <Stack gap={24}>
          <Stack gap={4}>
            <Text variant="h2">{title}</Text>
            <Text color="var(--ggui-color-neutral-500, #6b7280)">
              Help us improve by sharing your thoughts.
            </Text>
          </Stack>

          {renderProgressBar()}

          <div style={{
            minHeight: 300,
            animation: motionEnabled ? animation.slideInUp : 'none'
          }} key={step}>
            {renderStep()}
          </div>

          <Divider />

          <Row justify="between">
            {step > 1 ? (
              <Button
                variant="outline"
                leftIcon={<Icon name="chevron-left" size={16} />}
                onClick={handleBack}
              >
                Back
              </Button>
            ) : (
              <div />
            )}

            {step < totalSteps ? (
              <Button
                variant="primary"
                rightIcon={<Icon name="chevron-right" size={16} />}
                onClick={() => {
                  setTouched(t => ({ ...t, name: true, email: true, satisfaction: true }));
                  handleNext();
                }}
                disabled={!isStepValid}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                leftIcon={<Icon name="check" size={16} />}
                onClick={handleSubmit}
              >
                Submit Survey
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Icon,
  Divider,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

type Priority = 'low' | 'medium' | 'high';
type ColumnId = 'todo' | 'inprogress' | 'done';

interface Task {
  id: string;
  title: string;
  priority: Priority;
  assignee: string;
  dueDate?: string;
  column: ColumnId;
}

interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
  boardTitle?: string;
}

const COLUMNS: { id: ColumnId; label: string; variant: 'primary' | 'warning' | 'success' }[] = [
  { id: 'todo', label: 'To Do', variant: 'primary' },
  { id: 'inprogress', label: 'In Progress', variant: 'warning' },
  { id: 'done', label: 'Done', variant: 'success' },
];

export default function GeneratedComponent({
  initialTasks = [
    { id: '1', title: 'Design system review', priority: 'high', assignee: 'JD', column: 'todo', dueDate: '2023-12-01' },
    { id: '2', title: 'Fix navigation bugs', priority: 'medium', assignee: 'AS', column: 'inprogress' },
    { id: '3', title: 'Submit quarterly report', priority: 'low', assignee: 'JD', column: 'done' },
  ],
  onTaskUpdate,
  boardTitle = 'Project Roadmap',
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [addingToColumn, setAddingToColumn] = useState<ColumnId | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>('medium');

  const { motionEnabled } = useMotion();

  // Sync state with props if they change
  useEffect(() => {
    setTasks(initialTasks);
  }, [initialTasks]);

  const stats = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter((t) => t.column === 'done').length;
    const progress = total > 0 ? Math.round((completed / total) * 100) : 0;
    return { total, completed, progress };
  }, [tasks]);

  const updateTasks = (newTasks: Task[]) => {
    setTasks(newTasks);
    onTaskUpdate?.(newTasks);
  };

  const handleAddTask = (columnId: ColumnId) => {
    if (!newTaskTitle.trim()) return;

    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: 'ME', // Default assignee
      column: columnId,
      dueDate: new Date().toISOString().split('T')[0],
    };

    updateTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setAddingToColumn(null);
  };

  const handleMoveTask = (taskId: string, targetColumn: ColumnId) => {
    const updated = tasks.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t));
    updateTasks(updated);
  };

  const handleUpdateTaskTitle = (taskId: string, newTitle: string) => {
    const updated = tasks.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t));
    updateTasks(updated);
    setEditingTaskId(null);
  };

  const handleDeleteTask = (taskId: string) => {
    updateTasks(tasks.filter((t) => t.id !== taskId));
  };

  const getPriorityVariant = (priority: Priority) => {
    switch (priority) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'info';
      default: return 'default';
    }
  };

  const getPriorityColor = (priority: Priority) => {
    const variant = getPriorityVariant(priority);
    return 'var(--ggui-color-' + variant + '-500)';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header Summary Bar */}
        <Card
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            background: 'var(--ggui-color-primary-50, #f0f9ff)',
            border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
          }}
        >
          <Row justify="between" align="center" wrap>
            <Stack gap={4}>
              <Heading level={2} style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
                {boardTitle}
              </Heading>
              <Text color="var(--ggui-color-primary-700, #0369a1)">
                Keep track of your team's progress and tasks
              </Text>
            </Stack>
            <Row gap={24} align="center">
              <Stack align="center" gap={2}>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-500, #6b7280)">TOTAL TASKS</Text>
                <Text variant="h3" weight="bold">{stats.total}</Text>
              </Stack>
              <Divider orientation="vertical" margin={0} />
              <Stack align="center" gap={2}>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-500, #6b7280)">COMPLETED</Text>
                <Text variant="h3" weight="bold" color="var(--ggui-color-success-600, #16a34a)">{stats.completed}</Text>
              </Stack>
              <Divider orientation="vertical" margin={0} />
              <Stack align="center" gap={2}>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-500, #6b7280)">PROGRESS</Text>
                <Text variant="h3" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">{stats.progress + '%'}</Text>
              </Stack>
            </Row>
          </Row>
        </Card>

        {/* Board Columns */}
        <Row gap={16} align="start" style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          {COLUMNS.map((col) => {
            const columnTasks = tasks.filter((t) => t.column === col.id);
            return (
              <Stack
                key={col.id}
                gap={12}
                style={{
                  minWidth: 320,
                  flex: 1,
                  background: 'var(--ggui-color-neutral-50, #f9fafb)',
                  padding: 'var(--ggui-spacing-4, 16px)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                  minHeight: '600px',
                }}
                role="region"
                aria-label={col.label + ' column'}
              >
                {/* Column Header */}
                <Row justify="between" align="center">
                  <Row gap={8} align="center">
                    <div
                      style={{
                        width: 8,
                        height: 8,
                        borderRadius: '50%',
                        backgroundColor: 'var(--ggui-color-' + col.variant + '-500)',
                      }}
                    />
                    <Text weight="bold" variant="h4">{col.label}</Text>
                  </Row>
                  <Badge variant={col.variant}>{columnTasks.length}</Badge>
                </Row>

                {/* Task List */}
                <Stack gap={12}>
                  {columnTasks.map((task) => (
                    <Card
                      key={task.id}
                      padding="var(--ggui-spacing-4, 16px)"
                      shadow="sm"
                      style={{
                        animation: motionEnabled ? animation.slideInUp : 'none',
                        transition: transition.colors,
                        borderLeftWidth: '4px',
                        borderLeftStyle: 'solid',
                        borderLeftColor: getPriorityColor(task.priority),
                      }}
                    >
                      <Stack gap={12}>
                        {/* Task Content */}
                        <Stack gap={8}>
                          <Row justify="between" align="start">
                            {editingTaskId === task.id ? (
                              <Input
                                label="Edit Task Title"
                                value={task.title}
                                onChange={(val) => handleUpdateTaskTitle(task.id, val)}
                                autoFocus
                              />
                            ) : (
                              <Text
                                weight="semibold"
                                onDoubleClick={() => setEditingTaskId(task.id)}
                                style={{ cursor: 'pointer', flex: 1 }}
                              >
                                {task.title}
                              </Text>
                            )}
                            <Button
                              variant="ghost"
                              size="xs"
                              aria-label="Delete task"
                              onClick={() => handleDeleteTask(task.id)}
                            >
                              <Icon name="x" size={14} />
                            </Button>
                          </Row>
                          <Row gap={8} align="center" wrap>
                            <Badge variant={getPriorityVariant(task.priority)} size="sm">
                              {task.priority.toUpperCase()}
                            </Badge>
                            {task.dueDate && (
                              <Row gap={4} align="center">
                                <Icon name="settings" size={12} color="var(--ggui-color-neutral-500)" />
                                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                                  {task.dueDate}
                                </Text>
                              </Row>
                            )}
                          </Row>
                        </Stack>

                        <Divider margin={4} />

                        {/* Task Footer */}
                        <Row justify="between" align="center">
                          <Row gap={8} align="center">
                            <div
                              style={{
                                width: 28,
                                height: 28,
                                borderRadius: '50%',
                                background: 'var(--ggui-color-primary-100, #e0f2fe)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                              }}
                            >
                              <Text variant="caption" weight="bold" color="var(--ggui-color-primary-700, #0369a1)">
                                {task.assignee}
                              </Text>
                            </div>
                          </Row>

                          <Select
                            label="Move to"
                            value={task.column}
                            onChange={(val) => handleMoveTask(task.id, val as ColumnId)}
                            options={COLUMNS.map((c) => ({ value: c.id, label: c.label }))}
                            size="sm"
                          />
                        </Row>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {/* Add Task Control */}
                {addingToColumn === col.id ? (
                  <Card
                    padding="var(--ggui-spacing-3, 12px)"
                    style={{
                      border: '1px dashed var(--ggui-color-primary-300, #7dd3fc)',
                      background: 'var(--ggui-color-primary-50, #f0f9ff)',
                    }}
                  >
                    <Stack gap={12}>
                      <Input
                        label="Task Title"
                        placeholder="What needs to be done?"
                        value={newTaskTitle}
                        onChange={setNewTaskTitle}
                        required
                      />
                      <Select
                        label="Priority"
                        value={newTaskPriority}
                        onChange={(val) => setNewTaskPriority(val as Priority)}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Row gap={8}>
                        <Button variant="primary" size="sm" onClick={() => handleAddTask(col.id)} fullWidth>
                          Add Task
                        </Button>
                        <Button variant="ghost" size="sm" onClick={() => setAddingToColumn(null)}>
                          Cancel
                        </Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button
                    variant="ghost"
                    leftIcon={<Icon name="plus" size={16} />}
                    onClick={() => setAddingToColumn(col.id)}
                    fullWidth
                    style={{
                      marginTop: 'auto',
                      color: 'var(--ggui-color-neutral-500, #6b7280)',
                      justifyContent: 'start',
                    }}
                  >
                    Add Task
                  </Button>
                )}
              </Stack>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

