export default function GeneratedComponent({ 
  elements = DEFAULT_ELEMENTS,
  title = "Periodic Table of Elements",
  onSelectElement
}: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const { motionEnabled } = useMotion();

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerSearch = searchTerm.toLowerCase();
    return elements.filter(el => 
      el.name.toLowerCase().includes(lowerSearch) || 
      el.symbol.toLowerCase().includes(lowerSearch) ||
      String(el.number) === searchTerm
    );
  }, [elements, searchTerm]);

  const handleElementClick = (element: ElementData) => {
    setSelectedElement(element);
    if (onSelectElement) onSelectElement(element);
  };

  const getCategoryColor = (category: string) => CATEGORY_COLORS[category] || CATEGORY_COLORS.unknown;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        {/* Header Area */}
        <Stack gap={16}>
          <Row justify="between" align="center" wrap>
            <Text variant="h1" color="var(--ggui-color-primary-800, #075985)">{title}</Text>
            <div style={{ width: '100%', maxWidth: '400px' }}>
              <Input
                placeholder="Search by name, symbol, or number..."
                value={searchTerm}
                onChange={setSearchTerm}
                label="Search Elements"
              />
            </div>
          </Row>

          <Card padding="var(--ggui-spacing-4, 16px)">
            <Stack direction="horizontal" gap={12} wrap justify="center">
              {Object.entries(CATEGORY_LABELS).map(([key, label]) => (
                <Row key={key} gap={8} align="center">
                  <div style={{ 
                    width: 16, 
                    height: 16, 
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)', 
                    backgroundColor: getCategoryColor(key),
                    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)'
                  }} />
                  <Text variant="caption">{label}</Text>
                </Row>
              ))}
            </Stack>
          </Card>
        </Stack>

        {/* Layout with Table and Detail Panel */}
        <Row gap={24} align="start" wrap>
          {/* Periodic Table Grid */}
          <div style={{ 
            flex: '3 1 600px', 
            overflowX: 'auto', 
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            padding: 'var(--ggui-spacing-4, 16px)',
            boxShadow: 'inset 0 2px 4px rgba(0,0,0,0.02)'
          }}>
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(18, minmax(42px, 1fr))',
              gridAutoRows: 'minmax(50px, 1fr)',
              gap: '6px',
              minWidth: '850px'
            }}>
              {elements.map((el) => {
                const isFiltered = filteredElements.some(f => f.number === el.number);
                const isSelected = selectedElement?.number === el.number;

                return (
                  <button
                    key={el.number}
                    onClick={() => handleElementClick(el)}
                    aria-label={"Element " + el.number + ": " + el.name}
                    style={{
                      gridColumn: el.group,
                      gridRow: el.period,
                      backgroundColor: getCategoryColor(el.category),
                      border: isSelected 
                        ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                        : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      padding: '4px',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      justifyContent: 'center',
                      cursor: 'pointer',
                      opacity: isFiltered ? 1 : 0.15,
                      transform: isSelected ? 'scale(1.08)' : 'scale(1)',
                      transition: transition.normal,
                      zIndex: isSelected ? 10 : 1,
                      boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                      position: 'relative'
                    }}
                  >
                    <span style={{ 
                      position: 'absolute', 
                      top: 2, 
                      left: 2, 
                      fontSize: '9px', 
                      fontWeight: 'bold',
                      color: 'var(--ggui-color-neutral-700, #374151)'
                    }}>
                      {el.number}
                    </span>
                    <Text variant="body" weight="bold" style={{ fontSize: '15px', lineHeight: 1 }}>
                      {el.symbol}
                    </Text>
                  </button>
                );
              })}
            </div>

            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(18, minmax(42px, 1fr))',
              gap: '6px',
              minWidth: '850px',
              marginTop: '12px'
            }}>
              <div style={{ gridColumn: '1 / span 2', gridRow: '9' }}>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-500, #6b7280)">Lanthanides*</Text>
              </div>
              <div style={{ gridColumn: '1 / span 2', gridRow: '10' }}>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-500, #6b7280)">Actinides*</Text>
              </div>
            </div>

            <Text variant="caption" align="center" style={{ marginTop: 'var(--ggui-spacing-4, 16px)', color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
              Click an element cell to view detailed properties.
            </Text>
          </div>

          {/* Detail Panel */}
          <div style={{ flex: '1 1 320px' }}>
            {selectedElement ? (
              <Card 
                padding="var(--ggui-spacing-6, 24px)" 
                style={{ 
                  animation: motionEnabled ? animation.fadeIn : 'none',
                  borderTop: '4px solid ' + getCategoryColor(selectedElement.category)
                }}
              >
                <Stack gap={16}>
                  <Row justify="between" align="start">
                    <Stack gap={4}>
                      <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)">{selectedElement.name}</Text>
                      <Badge variant="primary">
                        {CATEGORY_LABELS[selectedElement.category]}
                      </Badge>
                    </Stack>
                    <div style={{ 
                      fontSize: '36px', 
                      fontWeight: 'bold', 
                      color: 'var(--ggui-color-primary-600, #0284c7)',
                      lineHeight: 1
                    }}>
                      {selectedElement.symbol}
                    </div>
                  </Row>

                  <Divider margin={8} />

                  <Stack gap={12}>
                    <Row justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Number</Text>
                      <Text weight="semibold">{selectedElement.number}</Text>
                    </Row>
                    <Row justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Weight</Text>
                      <Text weight="semibold">{selectedElement.weight + " u"}</Text>
                    </Row>
                    <Row justify="between">
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Group / Period</Text>
                      <Text weight="semibold">{selectedElement.group + " / " + (selectedElement.period < 9 ? selectedElement.period : (selectedElement.period === 9 ? '6*' : '7*'))}</Text>
                    </Row>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Electron Configuration</Text>
                      <div style={{ 
                        backgroundColor: 'var(--ggui-color-neutral-100, #f3f4f6)', 
                        padding: 'var(--ggui-spacing-2, 8px)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)'
                      }}>
                        <code style={{ fontSize: 'var(--ggui-font-size-sm, 14px)', color: 'var(--ggui-color-primary-800, #075985)' }}>
                          {selectedElement.electron_config}
                        </code>
                      </div>
                    </Stack>
                  </Stack>

                  <Button 
                    variant="ghost" 
                    fullWidth 
                    onClick={() => setSelectedElement(null)}
                    leftIcon={<Icon name="x" size={16} />}
                  >
                    Clear Selection
                  </Button>
                </Stack>
              </Card>
            ) : (
              <Card padding="var(--ggui-spacing-8, 32px)" border={false} style={{ textAlign: 'center', backgroundColor: 'transparent' }}>
                <Stack align="center" gap={16}>
                  <div style={{ 
                    width: 64, 
                    height: 64, 
                    borderRadius: '50%', 
                    backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    color: 'var(--ggui-color-primary-500, #0ea5e9)',
                    boxShadow: 'var(--ggui-shape-shadow-sm)'
                  }}>
                    <Icon name="search" size={32} />
                  </div>
                  <Stack gap={4}>
                    <Text variant="h3">Selection Required</Text>
                    <Text color="var(--ggui-color-neutral-500, #6b7280)">
                      Click on an element in the periodic table to view its chemical properties and atomic data.
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            )}
          </div>
        </Row>
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Button, 
  Badge, 
  Tabs, 
  Table, 
  Box, 
  Icon,
  MotionKeyframes,
  useMotion,
  Divider
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Specification {
  key: string;
  value: string;
}

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Props {
  productId?: string;
  name?: string;
  price?: number;
  currency?: string;
  rating?: number;
  stockStatus?: 'in-stock' | 'low-stock' | 'out-of-stock';
  stockCount?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  productId = 'prod-123',
  name = 'Premium Wireless Headphones',
  price = 299.99,
  currency = '$',
  rating = 4.5,
  stockStatus = 'low-stock',
  stockCount = 5,
  description = 'Experience crystal clear audio with our premium noise-canceling wireless headphones. Designed for comfort and long-lasting battery life, these headphones are perfect for travel, work, or casual listening.',
  specifications = [
    { key: 'Driver Size', value: '40mm' },
    { key: 'Battery Life', value: '30 hours' },
    { key: 'Connectivity', value: 'Bluetooth 5.2, 3.5mm jack' },
    { key: 'Weight', value: '250g' },
    { key: 'Noise Cancellation', value: 'Active Hybrid ANC' }
  ],
  reviews = [
    { author: 'Alex Johnson', rating: 5, text: 'The best headphones I have ever owned! Sound quality is superb.', date: '2023-10-15' },
    { author: 'Sarah Smith', rating: 4, text: 'Great noise cancellation, but the app could be better.', date: '2023-10-12' },
    { author: 'Mike Chen', rating: 5, text: 'Incredibly comfortable for long flights.', date: '2023-10-08' }
  ],
  onAddToCart
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const { motionEnabled } = useMotion();

  const handleIncrement = () => {
    if (quantity < stockCount) setQuantity(q => q + 1);
  };

  const handleDecrement = () => {
    if (quantity > 1) setQuantity(q => q - 1);
  };

  const handleAddToCart = () => {
    onAddToCart?.({ productId, quantity });
  };

  const renderStars = (currentRating: number) => {
    return (
      <Row gap={2} align="center" role="img" aria-label={"Rating: " + currentRating + " out of 5 stars"}>
        {[1, 2, 3, 4, 5].map((star) => (
          <Icon 
            key={star} 
            name="check" 
            size={16}
            color={star <= currentRating ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'}
          >
             <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
          </Icon>
        ))}
      </Row>
    );
  };

  const getBadgeVariant = () => {
    if (stockStatus === 'in-stock') return 'success';
    if (stockStatus === 'low-stock') return 'warning';
    return 'error';
  };

  const getBadgeLabel = () => {
    if (stockStatus === 'in-stock') return 'In Stock';
    if (stockStatus === 'low-stock') return 'Low Stock (' + stockCount + ' left)';
    return 'Out of Stock';
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Stack gap={32} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>

        {/* Top Section: Hero Layout */}
        <Stack 
          direction="vertical" 
          gap={24}
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            alignItems: 'start'
          }}
        >
          {/* Product Image Placeholder */}
          <Box 
            background="var(--ggui-color-primary-50, #f0f9ff)"
            padding={0}
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{ 
              aspectRatio: '1 / 1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              border: '2px dashed var(--ggui-color-primary-200, #bae6fd)',
              position: 'relative',
              overflow: 'hidden'
            }}
          >
            <Text 
              variant="h2" 
              weight="bold" 
              color="var(--ggui-color-primary-300, #7dd3fc)"
              align="center"
              style={{ padding: 'var(--ggui-spacing-4, 16px)', opacity: 0.5 }}
            >
              {name}
            </Text>
          </Box>

          {/* Product Info */}
          <Stack gap={16}>
            <Stack gap={8}>
              <Badge variant={getBadgeVariant()}>{getBadgeLabel()}</Badge>
              <Text variant="h1" weight="bold">{name}</Text>
              <Row gap={8} align="center">
                {renderStars(rating)}
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  ({reviews.length + " reviews"})
                </Text>
              </Row>
            </Stack>

            <Text variant="h2" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
              {currency + price.toLocaleString(undefined, { minimumFractionDigits: 2 })}
            </Text>

            <Divider />

            {/* Bottom Section (Action Area) */}
            <Stack gap={24}>
               <Stack gap={8}>
                <Text id="qty-label" variant="label" weight="medium">Quantity</Text>
                <Row gap={12} align="center">
                  <Box 
                    background="var(--ggui-color-neutral-100, #f3f4f6)" 
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{ border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}
                  >
                    <Row align="center">
                      <Button 
                        variant="ghost" 
                        size="sm"
                        onClick={handleDecrement}
                        disabled={quantity <= 1 || stockStatus === 'out-of-stock'}
                        aria-label="Decrease quantity"
                      >
                        <Icon name="minus" size={16} />
                      </Button>
                      <Box paddingX={12}>
                        <Text weight="bold" style={{ minWidth: '20px', textAlign: 'center' }}>
                          {quantity}
                        </Text>
                      </Box>
                      <Button 
                        variant="ghost" 
                        size="sm"
                        onClick={handleIncrement}
                        disabled={quantity >= stockCount || stockStatus === 'out-of-stock'}
                        aria-label="Increase quantity"
                      >
                        <Icon name="plus" size={16} />
                      </Button>
                    </Row>
                  </Box>
                  {stockStatus === 'low-stock' && (
                    <Text variant="caption" color="var(--ggui-color-warning-600, #d97706)">
                      {"Only " + stockCount + " left!"}
                    </Text>
                  )}
                </Row>
              </Stack>

              <Button 
                variant="primary" 
                size="lg" 
                fullWidth 
                onClick={handleAddToCart}
                disabled={stockStatus === 'out-of-stock'}
                leftIcon={<Icon name="check" size={20} />} 
                style={{ transition: transition.colors }}
              >
                {stockStatus === 'out-of-stock' ? 'Out of Stock' : 'Add to Cart'}
              </Button>
            </Stack>
          </Stack>
        </Stack>

        {/* Middle Section: Tab Navigation */}
        <Card padding={0} shadow="md">
          <Tabs 
            variant="line"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Box padding="var(--ggui-spacing-6, 24px)">
                    <Stack gap={16}>
                      <Text variant="h3">Product Details</Text>
                      <Text color="var(--ggui-color-neutral-700, #374151)" style={{ lineHeight: '1.6' }}>
                        {description}
                      </Text>
                    </Stack>
                  </Box>
                )
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: (
                  <Box padding="var(--ggui-spacing-6, 24px)">
                    <Table 
                      columns={[
                        { key: 'key', header: 'Feature', width: '40%', render: (val) => <Text weight="semibold">{String(val)}</Text> },
                        { key: 'value', header: 'Specification' }
                      ]}
                      data={specifications}
                      bordered
                      striped
                    />
                  </Box>
                )
              },
              {
                key: 'reviews',
                label: "Reviews (" + reviews.length + ")",
                content: (
                  <Box padding="var(--ggui-spacing-6, 24px)">
                    <Stack gap={16}>
                      {reviews.map((review, idx) => (
                        <Card key={idx} padding={16} border shadow="none">
                          <Stack gap={8}>
                            <Row justify="between" align="center">
                              <Text weight="bold">{review.author}</Text>
                              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{review.date}</Text>
                            </Row>
                            <Row gap={4}>{renderStars(review.rating)}</Row>
                            <Text color="var(--ggui-color-neutral-700, #374151)">{review.text}</Text>
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  </Box>
                )
              }
            ]}
          />
        </Card>

      </Stack>
    </Container>
  );
}

import { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Icon,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender: string;
  senderId?: string;
  text: string;
  timestamp: string;
}

interface User {
  id: string;
  name: string;
}

interface Props {
  conversationTitle?: string;
  participantsCount?: number;
  user?: User;
  initialMessages?: Message[];
  onSend?: (data: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  conversationTitle = "Team Chat",
  participantsCount = 3,
  user = { id: "user-1", name: "You" },
  initialMessages = [
    { sender: "Alice", senderId: "user-2", text: "Hey everyone! How is the project going?", timestamp: "10:30 AM" },
    { sender: "Bob", senderId: "user-3", text: "Just finished the design phase.", timestamp: "10:32 AM" }
  ],
  onSend
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const typingTimeoutRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  // Handle auto-scroll to bottom
  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, typingUser]);

  // Real-time event listener using a safer access pattern
  useEffect(() => {
    const safeWindow = typeof window !== 'undefined' ? window : null;
    if (!safeWindow) return;

    const handler = (e: any) => {
      const data = e.detail;
      if (!data) return;

      const { type, sender, senderId, text, timestamp } = data;

      if (type === 'message') {
        setMessages(prev => [...prev, { sender, senderId, text, timestamp }]);
        setTypingUser(null);
      } else if (type === 'typing') {
        setTypingUser(sender);

        if (typingTimeoutRef.current) {
          clearTimeout(typingTimeoutRef.current);
        }

        typingTimeoutRef.current = setTimeout(() => {
          setTypingUser(null);
        }, 3000);
      }
    };

    safeWindow.addEventListener('ggui:agent-data', handler);
    return () => {
      safeWindow.removeEventListener('ggui:agent-data', handler);
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    };
  }, []);

  const handleSend = () => {
    if (!inputValue.trim()) return;

    const timestamp = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const newMessage: Message = {
      sender: user.name,
      senderId: user.id,
      text: inputValue,
      timestamp
    };

    setMessages(prev => [...prev, newMessage]);
    setInputValue('');
    onSend?.({ text: inputValue, timestamp });
  };

  const handleKeyPress = (e: any) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Container maxWidth="md" padding={0}>
      <MotionKeyframes />
      <Card 
        padding={0} 
        shadow="lg" 
        border={false} 
        style={{ 
          height: '600px', 
          display: 'flex', 
          flexDirection: 'column', 
          overflow: 'hidden',
          backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)'
        }}
      >

        {/* Header */}
        <Box 
          padding="var(--ggui-spacing-4, 16px)" 
          style={{ 
            background: 'linear-gradient(to bottom, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-700, #0369a1))',
            color: '#ffffff'
          }}
        >
          <Row justify="between" align="center">
            <Stack gap={2}>
              <Text variant="h3" color="inherit" weight="bold">{conversationTitle}</Text>
              <Text variant="caption" color="var(--ggui-color-primary-100, #e0f2fe)">
                {participantsCount} participants
              </Text>
            </Stack>
            <Button variant="ghost" aria-label="Settings" style={{ color: '#ffffff', minWidth: 'auto', padding: 'var(--ggui-spacing-2, 8px)' }}>
              <Icon name="settings" size={20} />
            </Button>
          </Row>
        </Box>

        {/* Message Area */}
        <Box 
          ref={scrollRef as any}
          padding="var(--ggui-spacing-4, 16px)"
          style={{ 
            flex: 1, 
            overflowY: 'auto', 
            scrollBehavior: 'smooth'
          }}
        >
          <Stack gap={12}>
            {messages.map((msg, index) => {
              const isMe = msg.senderId === user.id;
              return (
                <Stack 
                  key={index} 
                  align={isMe ? 'end' : 'start'} 
                  gap={4}
                  style={{ 
                    animation: motionEnabled ? animation.fadeIn : 'none',
                    animationDelay: (index * 20) + 'ms'
                  }}
                >
                  {!isMe && (
                    <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500, #6b7280)">
                      {msg.sender}
                    </Text>
                  )}
                  <Box
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    style={{
                      maxWidth: '80%',
                      background: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-100, #f3f4f6)',
                      color: isMe ? '#ffffff' : 'var(--ggui-color-neutral-900, #111827)',
                      boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                      borderBottomRightRadius: isMe ? 'var(--ggui-shape-radius-sm, 4px)' : 'var(--ggui-shape-radius-lg, 12px)',
                      borderBottomLeftRadius: !isMe ? 'var(--ggui-shape-radius-sm, 4px)' : 'var(--ggui-shape-radius-lg, 12px)',
                    }}
                  >
                    <Text color="inherit">{msg.text}</Text>
                  </Box>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                    {msg.timestamp}
                  </Text>
                </Stack>
              );
            })}

            {/* Typing Indicator */}
            {typingUser && (
              <Stack align="start" gap={4} style={{ animation: animation.fadeIn }}>
                <Box
                  padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  background="var(--ggui-color-neutral-100, #f3f4f6)"
                  style={{ borderBottomLeftRadius: 'var(--ggui-shape-radius-sm, 4px)' }}
                >
                  <Row gap={4} align="center">
                    <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500, #6b7280)">
                      {typingUser} is typing...
                    </Text>
                    <Row gap={2}>
                      <div style={{ width: 4, height: 4, borderRadius: '50%', background: 'currentColor', opacity: 0.6 }} />
                      <div style={{ width: 4, height: 4, borderRadius: '50%', background: 'currentColor', opacity: 0.6 }} />
                      <div style={{ width: 4, height: 4, borderRadius: '50%', background: 'currentColor', opacity: 0.6 }} />
                    </Row>
                  </Row>
                </Box>
              </Stack>
            )}
          </Stack>
        </Box>

        {/* Input Area */}
        <Box 
          padding="var(--ggui-spacing-4, 16px)" 
          style={{ 
            background: '#ffffff', 
            borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' 
          }}
        >
          <Stack gap={8} role="form" aria-label="Message composition">
            <Row gap={8} align="end">
              <Box style={{ flex: 1 }}>
                <Input
                  label="Message"
                  placeholder="Type a message..."
                  value={inputValue}
                  onChange={setInputValue}
                  onKeyDown={handleKeyPress}
                />
              </Box>
              <Button 
                variant="primary" 
                onClick={handleSend}
                disabled={!inputValue.trim()}
                aria-label="Send message"
                style={{ height: '44px' }}
              >
                <Icon name="plus" size={20} style={{ transform: 'rotate(45deg)' }} />
              </Button>
            </Row>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}
